dashboard.definition:
{
  "title": "Source - GCP Audit",
  "description": "Why index GCP Audit? Track cloud resource changes and detect privilege escalation",
  "dataSources": {
    "ds_total_events": {
      "type": "ds.search",
      "name": "Total Audit Events Over Time",
      "options": {
        "query": "| tstats count where index=fake_tshrt (sourcetype=\"FAKE:google:gcp:pubsub:audit:admin_activity\" OR sourcetype=\"FAKE:google:gcp:pubsub:audit:data_access\") by _time span=1h"
      }
    },
    "ds_admin_activity": {
      "type": "ds.search",
      "name": "Admin Activity Count",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:google:gcp:pubsub:audit:admin_activity\" | stats count"
      }
    },
    "ds_permission_changes": {
      "type": "ds.search",
      "name": "Permission Changes",
      "options": {
        "query": "index=fake_tshrt (sourcetype=\"FAKE:google:gcp:pubsub:audit:admin_activity\" OR sourcetype=\"FAKE:google:gcp:pubsub:audit:data_access\") | spath path=protoPayload.methodName output=method | search method=\"*.setIamPolicy\" OR method=\"*.SetIamPolicy\" | stats count"
      }
    },
    "ds_unique_principals": {
      "type": "ds.search",
      "name": "Unique Principals",
      "options": {
        "query": "index=fake_tshrt (sourcetype=\"FAKE:google:gcp:pubsub:audit:admin_activity\" OR sourcetype=\"FAKE:google:gcp:pubsub:audit:data_access\") user=* | stats dc(user) as count"
      }
    },
    "ds_events_over_time": {
      "type": "ds.search",
      "name": "Audit Events Over Time by Service",
      "options": {
        "query": "index=fake_tshrt (sourcetype=\"FAKE:google:gcp:pubsub:audit:admin_activity\" OR sourcetype=\"FAKE:google:gcp:pubsub:audit:data_access\") | spath path=protoPayload.serviceName output=service | fillnull value=\"unknown\" service | timechart span=1h count by service"
      }
    },
    "ds_by_service": {
      "type": "ds.search",
      "name": "Events by Service",
      "options": {
        "query": "index=fake_tshrt (sourcetype=\"FAKE:google:gcp:pubsub:audit:admin_activity\" OR sourcetype=\"FAKE:google:gcp:pubsub:audit:data_access\") | spath path=protoPayload.serviceName output=service | fillnull value=\"unknown\" service | stats count by service | sort -count"
      }
    },
    "ds_top_principals": {
      "type": "ds.search",
      "name": "Top Principals by Activity",
      "options": {
        "query": "index=fake_tshrt (sourcetype=\"FAKE:google:gcp:pubsub:audit:admin_activity\" OR sourcetype=\"FAKE:google:gcp:pubsub:audit:data_access\") user=* | stats count by user | sort -count | head 15 | rename user as \"Principal\""
      }
    },
    "ds_sample_events": {
      "type": "ds.search",
      "name": "Recent Admin Activity Events",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:google:gcp:pubsub:audit:admin_activity\" | spath path=protoPayload.serviceName output=service | spath path=protoPayload.methodName output=method | spath path=protoPayload.resourceName output=resource | table _time user method service resource | sort -_time | head 30 | rename user as \"Principal\" method as \"Method\" service as \"Service\" resource as \"Resource\""
      }
    }
  },
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# Source — GCP Audit\n\n**Sourcetypes:** `FAKE:google:gcp:pubsub:audit:admin_activity`, `FAKE:google:gcp:pubsub:audit:data_access` | **Project:** faketshirtcompany-prod-01 (us-central1) | **Format:** JSON (via Pub/Sub)\n\n**Why monitor?** Track cloud resource changes, detect privilege escalation via IAM policy modifications, and audit who is accessing what in your GCP environment.",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_kpi_total_events": {
      "type": "splunk.singlevalue",
      "title": "Total Audit Events",
      "dataSources": { "primary": "ds_total_events" },
      "options": {
        "majorValue": "> sparklineValues | lastPoint()",
        "sparklineValues": "> primary | seriesByName('count')",
        "sparklineDisplay": "below",
        "majorColor": "#00D2FF",
        "backgroundColor": "transparent",
        "showSparklineAreaGraph": true,
        "sparklineStrokeColor": "#00D2FF"
      }
    },
    "viz_kpi_admin": {
      "type": "splunk.singlevalue",
      "title": "Admin Activity",
      "dataSources": { "primary": "ds_admin_activity" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#F8BE34",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_permissions": {
      "type": "splunk.singlevalue",
      "title": "Permission Changes",
      "dataSources": { "primary": "ds_permission_changes" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#DC4E41",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_principals": {
      "type": "splunk.singlevalue",
      "title": "Unique Principals",
      "dataSources": { "primary": "ds_unique_principals" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#7B56DB",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_events_over_time": {
      "type": "splunk.area",
      "title": "Audit Events Over Time by Service",
      "dataSources": { "primary": "ds_events_over_time" },
      "options": {
        "stackMode": "stacked",
        "legendDisplay": "right",
        "nullValueDisplay": "zero",
        "areaOpacity": 0.7,
        "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Events / hour",
        "yAxisTitleVisibility": "show",
        "yAxisAbbreviation": "auto",
        "seriesColors": ["#00D2FF", "#7B56DB", "#53A051", "#F8BE34", "#DC4E41", "#009CEB"]
      },
      "showProgressBar": true,
      "showLastUpdated": true
    },
    "viz_by_service": {
      "type": "splunk.pie",
      "title": "Events by Service",
      "dataSources": { "primary": "ds_by_service" },
      "options": {
        "labelDisplay": "valuesAndPercentage",
        "showDonutHole": true,
        "seriesColors": ["#00D2FF", "#7B56DB", "#53A051", "#F8BE34", "#DC4E41", "#009CEB"]
      }
    },
    "viz_top_principals": {
      "type": "splunk.bar",
      "title": "Top Principals by Activity",
      "dataSources": { "primary": "ds_top_principals" },
      "options": {
        "seriesColors": ["#7B56DB"],
        "legendDisplay": "off",
        "xAxisTitleText": "Events",
        "xAxisTitleVisibility": "show",
        "yAxisTitleVisibility": "hide",
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_sample_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "### Recent Admin Activity Events",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_sample_events": {
      "type": "splunk.table",
      "title": "Recent Admin Activity",
      "dataSources": { "primary": "ds_sample_events" },
      "options": {
        "count": 20,
        "showRowNumbers": false
      },
      "showProgressBar": true,
      "showLastUpdated": true
    }
  },
  "inputs": {
    "input_global_trp": {
      "type": "input.timerange",
      "title": "Time Range",
      "options": {
        "token": "global_time",
        "defaultValue": "1767225600,1769904000"
      }
    }
  },
  "defaults": {
    "dataSources": {
      "ds.search": {
        "options": {
          "queryParameters": {
            "earliest": "$global_time.earliest$",
            "latest": "$global_time.latest$"
          }
        }
      }
    }
  },
  "layout": {
    "type": "grid",
    "globalInputs": ["input_global_trp"],
    "structure": [
      { "item": "viz_header", "type": "block", "position": { "x": 0, "y": 0, "w": 1200, "h": 120 } },
      { "item": "viz_kpi_total_events", "type": "block", "position": { "x": 0, "y": 120, "w": 300, "h": 120 } },
      { "item": "viz_kpi_admin", "type": "block", "position": { "x": 300, "y": 120, "w": 300, "h": 120 } },
      { "item": "viz_kpi_permissions", "type": "block", "position": { "x": 600, "y": 120, "w": 300, "h": 120 } },
      { "item": "viz_kpi_principals", "type": "block", "position": { "x": 900, "y": 120, "w": 300, "h": 120 } },
      { "item": "viz_events_over_time", "type": "block", "position": { "x": 0, "y": 240, "w": 750, "h": 350 } },
      { "item": "viz_by_service", "type": "block", "position": { "x": 750, "y": 240, "w": 450, "h": 350 } },
      { "item": "viz_top_principals", "type": "block", "position": { "x": 0, "y": 590, "w": 1200, "h": 300 } },
      { "item": "viz_sample_header", "type": "block", "position": { "x": 0, "y": 890, "w": 1200, "h": 50 } },
      { "item": "viz_sample_events", "type": "block", "position": { "x": 0, "y": 940, "w": 1200, "h": 400 } }
    ]
  }
}
